def solve(arg1: dict) -> list[dict]:
    # Mock database and roles for demonstration purposes
    roles_db = [
        {'id': 1, 'name': 'Admin'},
        {'id': 2, 'name': 'User'}
    ]

    user_roles = {
        'user1': {'roles': [1]},
        'user2': {'roles': []}
    }

    action = arg1.get('action')

    if action == 'get_roles_with_selector':
        selector = arg1.get('selector', [])
        return [{key: role[key] for key in selector} for role in roles_db]

    elif action == 'assign_role':
        user_id = arg1.get('user_id')
        role_id = arg1.get('role_id')
        if user_id in user_roles:
            user_roles[user_id]['roles'].append(role_id)
            return {'roleId': role_id, 'status': 'assigned'}
        else:
            return {'error': 'User not found'}

    elif action == 'deassign_role':
        user_id = arg1.get('user_id')
        role_id = arg1.get('role_id')
        if user_id in user_roles and role_id in user_roles[user_id]['roles']:
            user_roles[user_id]['roles'].remove(role_id)
            return {'roleId': role_id, 'status': 'deassigned'}
        else:
            return {'error': 'User not found or role not assigned'}

    elif action == 'has_role':
        user_id = arg1.get('user_id')
        role_id = arg1.get('role_id')
        if user_id in user_roles:
            return role_id in user_roles[user_id]['roles']
        else:
            return False

    return None
